import React, { useState } from "react";
import axios from "axios";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-lg mx-auto p-8 bg-gradient-to-r from-green-400 via-blue-500 to-purple-600 shadow-2xl rounded-lg border border-gray-300 text-white">
            <h2 className="text-4xl font-bold text-red text-center mb-6 drop-shadow-lg">🌾 Crop Price Lookup 🌾</h2>
            
            <div className="space-y-5">
                <select 
                    value={commodity} 
                    onChange={(e) => setCommodity(e.target.value)} 
                    className="w-full p-4 border rounded-lg bg-white text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400"
                >
                    <option value="">Select Commodity</option>
                    {commodityOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </select>

                <select 
                    value={district} 
                    onChange={(e) => setDistrict(e.target.value)} 
                    className="w-full p-4 border rounded-lg bg-white text-gray-900 shadow-lg focus:ring-2 focus:ring-yellow-400"
                >
                    <option value="">Select District</option>
                    {districtOptions.map((item, index) => (
                        <option key={index} value={item}>{item}</option>
                    ))}
                </select>
            </div>
            
            <button 
                onClick={fetchPrices} 
                className="w-full mt-6 p-4 bg-yellow-400 text-gray-900 font-bold rounded-lg shadow-xl hover:bg-yellow-500 transition-transform transform hover:scale-105"
            >
                🔍 Get Prices
            </button>
            
            {loading && <p className="text-center mt-4 text-white animate-pulse">Loading...</p>}
            {error && <p className="text-center mt-4 text-red-200 font-bold">{error}</p>}
            
            {prices && (
                <div className="mt-8 p-6 bg-white text-gray-900 rounded-lg shadow-2xl">
                    <h3 className="text-2xl font-semibold text-gray-700 text-center mb-4">📊 Price Details 📊</h3>
                    <div className="space-y-4">
                        {prices.map((data, index) => (
                            <div key={index} className="p-4 bg-gradient-to-r from-yellow-300 to-orange-400 shadow-md rounded-lg border border-gray-300">
                                <p className="font-semibold"><strong>Grade:</strong> {data.Grade}</p>
                                <p><strong>Min Price:</strong> {data["Min Price"]} ₹</p>
                                <p><strong>Max Price:</strong> {data["Max Price"]} ₹</p>
                                <p><strong>Modal Price:</strong> {data["Modal Price"]} ₹</p>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default CropPriceLookup;
